// registry/new-york/data-grid/use-table.ts
import { useRef, useState } from 'react'

import {
    ColumnMeta,
    FieldErrors,
    PaginationState,
    Resource,
    SortDirection,
    SortState,
    TableProps,
    UseTableOptions,
    ValidationFn,
} from './types'

export function useTable<TData extends Resource>({
    data,
    fields,
    validation,
    onSave,
    onCreate,
    onDelete,
    onView,
    extraActions,
    pagination: paginationOptions,
    sort: sortOptions,
}: UseTableOptions<TData>) {
    const [editingRowId, setEditingRowId] = useState<TData['id'] | null>(null)
    const [isSubmitting, setIsSubmitting] = useState(false)
    const [createErrors, setCreateErrors] = useState<FieldErrors>({})
    const [editErrors, setEditErrors] = useState<FieldErrors>({})
    const [page, setPage] = useState(paginationOptions?.page ?? 0)
    const [pageSize, setPageSize] = useState(paginationOptions?.pageSize ?? 10)
    const [sortState, setSortState] = useState<SortState | null>(null)

    const isServerSide = paginationOptions?.total !== undefined
    const total = isServerSide ? (paginationOptions?.total ?? 0) : data.length

    const columns: ColumnMeta<TData>[] = (Object.keys(fields) as Array<keyof TData>).map(key => {
        const field = fields[key]!
        return { key, label: field.label, size: field.size, sortable: field.sortable, field }
    })

    const validate = (formData: Partial<TData>): FieldErrors => {
        if (!validation) return {}
        const errors: FieldErrors = {}
        ;(Object.keys(validation) as Array<keyof TData>).forEach(key => {
            const fn = (validation as ValidationFn<TData>)[key]
            if (!fn) return
            const result = fn(formData[key], formData)
            if (result) errors[String(key)] = result
        })
        return errors
    }

    const editingRowIdRef = useRef<TData['id'] | null>(null)

    const onEdit = (id: TData['id']) => {
        setEditingRowId(id)
        editingRowIdRef.current = id
        setEditErrors({})
    }

    const onCancelEdit = () => {
        setEditingRowId(null)
        editingRowIdRef.current = null
        setEditErrors({})
    }

    const handleSave = async (id: TData['id'], formData: Partial<TData>) => {
        const payload = Object.fromEntries(
            Object.entries(formData).filter(([key]) => {
                const field = fields[key as keyof TData]
                return field?.type !== 'readonly'
            }),
        ) as Partial<TData>

        const validationErrors = validate(payload)
        if (Object.keys(validationErrors).length > 0) {
            setEditErrors(validationErrors)
            throw new Error('Validation failed')
        }
        try {
            setIsSubmitting(true)
            await onSave?.(id, formData)
            setEditingRowId(null)
            setEditErrors({})
            editingRowIdRef.current = null
        } catch (e) {
            throw e
        } finally {
            setIsSubmitting(false)
        }
    }

    const handleCreate = async (formData: Partial<TData>) => {
        const validationErrors = validate(formData)
        if (Object.keys(validationErrors).length > 0) {
            setCreateErrors(validationErrors)
            throw new Error('Validation failed')
        }
        try {
            setIsSubmitting(true)
            setCreateErrors({})
            await onCreate?.(formData)
        } catch (e) {
            throw e
        } finally {
            setIsSubmitting(false)
        }
    }

    const handleDelete = async (id: TData['id']) => {
        await onDelete?.(id)
    }

    const handlePageChange = (newPage: number) => {
        setPage(newPage)
        paginationOptions?.onPageChange?.(newPage, pageSize)
    }

    const handlePageSizeChange = (newSize: number) => {
        setPageSize(newSize)
        setPage(0)
        paginationOptions?.onPageChange?.(0, newSize)
    }

    const handleSort = (key: string, direction: SortDirection) => {
        setSortState({ key, direction })
        sortOptions?.onSortChange?.(key, direction)
    }

    // client-side sort
    const sortData = (rows: TData[]): TData[] => {
        if (!sortState || sortOptions?.onSortChange) return rows // skip if server-side
        const { key, direction } = sortState
        return [...rows].sort((a, b) => {
            const aVal = a[key as keyof TData]
            const bVal = b[key as keyof TData]
            if (aVal === null || aVal === undefined) return 1
            if (bVal === null || bVal === undefined) return -1
            if (aVal instanceof Date && bVal instanceof Date) {
                return direction === 'asc' ? aVal.getTime() - bVal.getTime() : bVal.getTime() - aVal.getTime()
            }
            if (typeof aVal === 'number' && typeof bVal === 'number') {
                return direction === 'asc' ? aVal - bVal : bVal - aVal
            }
            const aStr = String(aVal).toLowerCase()
            const bStr = String(bVal).toLowerCase()
            if (direction === 'asc') return aStr.localeCompare(bStr)
            return bStr.localeCompare(aStr)
        })
    }

    const rawRows = paginationOptions
        ? isServerSide
            ? data
            : data.slice(page * pageSize, page * pageSize + pageSize)
        : data

    const rows = sortData(rawRows)

    const setError = (field: keyof TData, message: string) => {
        if (editingRowIdRef.current !== null) {
            setEditErrors(prev => ({ ...prev, [String(field)]: message }))
        } else {
            setCreateErrors(prev => ({ ...prev, [String(field)]: message }))
        }
    }

    const paginationState: PaginationState | undefined = paginationOptions
        ? { page, pageSize, total, onPageChange: handlePageChange, onPageSizeChange: handlePageSizeChange }
        : undefined

    const onCancelCreate = () => {
        setCreateErrors({})
    }

    const tableProps: TableProps<TData> = {
        rows,
        columns,
        editingRowId,
        isSubmitting,
        createErrors,
        editErrors,
        onSave: handleSave,
        onCancelEdit,
        onCreate: handleCreate,
        onDelete: handleDelete,
        onView,
        onEdit,
        extraActions,
        pagination: paginationState,
        onCancelCreate,
        sort: sortState,
        onSort: handleSort,
    }

    return {
        tableProps,
        setError,
        setCreateErrors,
        setEditErrors,
    }
}

import { cn } from '@/lib/utils'

import { DataTable } from '@/components/data-grid/data-table'
import { DataTablePagination } from '@/components/data-grid/data-table-pagination'
import { DataGridProps, Resource } from '@/components/data-grid/types'

export const DataGrid = <TData extends Resource>({
    tableProps,
    className,
    isLoading,
    customEmptyMessage,
}: DataGridProps<TData>) => {
    return (
        <div className={cn('flex w-full flex-col items-center space-y-2', className)}>
            <DataTable tableProps={tableProps} isLoading={isLoading} customEmptyMessage={customEmptyMessage} />
            {tableProps.pagination && <DataTablePagination pagination={tableProps.pagination} />}
        </div>
    )
}

import React from 'react'

import { ChevronDown, ChevronsUpDown, ChevronUp } from 'lucide-react'

import { Button } from '@/components/ui/button'
import { Scroller } from '@/components/ui/scroller'
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table'

import { DataTableActions } from '@/components/data-grid/data-table-actions'
import { DataTableCreateRow } from '@/components/data-grid/data-table-create-row'
import { DataTableEditRow } from '@/components/data-grid/data-table-edit-row'
import { DataTableProgressSpinner } from '@/components/data-grid/data-table-progress-spinner'
import { FieldDef, Resource, SortDirection, TableProps } from '@/components/data-grid/types'

interface DataTableProps<TData extends Resource> {
    tableProps: TableProps<TData>
    isLoading?: boolean
    customEmptyMessage?: string
}

export function DataTable<TData extends Resource>({
    tableProps,
    isLoading,
    customEmptyMessage = 'No Results.',
}: DataTableProps<TData>) {
    const {
        rows,
        columns,
        editingRowId,
        isSubmitting,
        createErrors,
        editErrors,
        onSave,
        onCancelEdit,
        onCreate,
        onDelete,
        onView,
        onEdit,
        extraActions,
        onCancelCreate,
        sort,
        onSort,
    } = tableProps

    const handleSort = (key: string) => {
        if (!onSort) return
        if (sort?.key === key) {
            // same column — toggle direction
            const nextDirection: SortDirection = sort.direction === 'asc' ? 'desc' : 'asc'
            onSort(key, nextDirection)
        } else {
            // new column — start with asc
            onSort(key, 'asc')
        }
    }

    const cellStyle = (size?: number) =>
        size !== undefined
            ? { minWidth: `${size}px`, width: `${size}px`, maxWidth: `${size}px`, overflow: 'hidden' as const }
            : undefined

    return (
        <Scroller size={0} className='relative max-h-150 min-h-0 w-full rounded-md border'>
            {isLoading && <DataTableProgressSpinner isFetching={isLoading} />}
            <Table className='w-full'>
                <TableHeader className='bg-muted'>
                    <TableRow>
                        {columns.map(col => {
                            const isSorted = sort?.key === String(col.key)
                            const direction = isSorted ? sort?.direction : undefined
                            return (
                                <TableHead
                                    key={String(col.key)}
                                    className='bg-muted sticky top-0 z-10'
                                    style={
                                        col.size !== undefined
                                            ? {
                                                  minWidth: `${col.size}px`,
                                                  width: `${col.size}px`,
                                              }
                                            : undefined
                                    }
                                >
                                    <div className='flex items-center gap-1'>
                                        <span>{col.label}</span>
                                        {col.sortable && (
                                            <Button
                                                variant='ghost'
                                                size='icon'
                                                className='h-6 w-6 shrink-0'
                                                onClick={() => handleSort(String(col.key))}
                                            >
                                                {!isSorted && (
                                                    <ChevronsUpDown className='text-muted-foreground h-3 w-3' />
                                                )}
                                                {isSorted && direction === 'asc' && <ChevronUp className='h-3 w-3' />}
                                                {isSorted && direction === 'desc' && (
                                                    <ChevronDown className='h-3 w-3' />
                                                )}
                                            </Button>
                                        )}
                                    </div>
                                </TableHead>
                            )
                        })}
                        <TableHead
                            className='bg-muted sticky top-0 z-10'
                            style={{ width: '1px', whiteSpace: 'nowrap' }}
                        />
                    </TableRow>
                </TableHeader>
                <TableBody>
                    {onCreate && (
                        <DataTableCreateRow
                            columns={columns}
                            onCreate={onCreate}
                            isSubmitting={isSubmitting}
                            errors={createErrors}
                            onCancel={onCancelCreate}
                        />
                    )}

                    {rows.length ? (
                        rows.map(row => {
                            const isEditing =
                                editingRowId !== null && editingRowId !== undefined && row.id === editingRowId

                            if (isEditing) {
                                return (
                                    <DataTableEditRow
                                        key={row.id}
                                        row={row}
                                        columns={columns}
                                        onSave={onSave}
                                        onCancel={onCancelEdit}
                                        isSubmitting={isSubmitting}
                                        errors={editErrors}
                                    />
                                )
                            }

                            return (
                                <TableRow key={row.id}>
                                    {columns.map(col => {
                                        const value = row[col.key]
                                        const field = col.field

                                        if (field?.render) {
                                            return (
                                                <TableCell
                                                    key={String(col.key)}
                                                    className='border-border border-r last:border-r-0'
                                                    style={cellStyle(col.size)}
                                                >
                                                    {field.render(value as TData[keyof TData], row)}
                                                </TableCell>
                                            )
                                        }

                                        return (
                                            <TableCell
                                                key={String(col.key)}
                                                className='border-border border-r last:border-r-0'
                                                style={cellStyle(col.size)}
                                            >
                                                {autoRender(value, field)}
                                            </TableCell>
                                        )
                                    })}
                                    <TableCell style={{ width: '1px', whiteSpace: 'nowrap' }}>
                                        <DataTableActions
                                            resource={row}
                                            onEdit={onEdit}
                                            onDelete={onDelete}
                                            onView={onView}
                                            extraActions={extraActions}
                                        />
                                    </TableCell>
                                </TableRow>
                            )
                        })
                    ) : (
                        <TableRow>
                            <TableCell colSpan={columns.length + 1} className='h-24 text-center'>
                                {customEmptyMessage}
                            </TableCell>
                        </TableRow>
                    )}
                </TableBody>
            </Table>
        </Scroller>
    )
}

function autoRender<TData extends Resource>(value: unknown, field: FieldDef<TData> | undefined): React.ReactNode {
    if (value === null || value === undefined) return <span className='text-muted-foreground'>—</span>

    if (!field) return <span>{String(value)}</span>

    switch (field.type) {
        case 'checkbox':
            return <span>{value ? 'Yes' : 'No'}</span>
        case 'date':
            return <span>{value instanceof Date ? value.toLocaleDateString() : String(value)}</span>
        case 'select': {
            const option = field.options.find(o => o.value === value)
            return <span>{option?.label ?? String(value)}</span>
        }
        case 'virtualized-dropdown': {
            const nameSet = field.nameSet
            if (typeof value === 'object' && value !== null) {
                if (typeof nameSet === 'function') return <span>{nameSet(value as Record<string, unknown>)}</span>
                if (typeof nameSet === 'string')
                    return <span>{(value as Record<string, unknown>)[nameSet] as string}</span>
            }
            return <span>{String(value)}</span>
        }
        case 'number':
            return (
                <span>
                    {typeof value === 'number'
                        ? field.thousandSeparator
                            ? value.toLocaleString()
                            : value
                        : String(value)}
                </span>
            )
        default:
            return <span>{String(value)}</span>
    }
}

import { Eye, MoreVertical, SquarePen, Trash2 } from 'lucide-react'

import { Button } from '@/components/ui/button'
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from '@/components/ui/dropdown-menu'

import { ExtraAction, Resource } from './types'

interface Props<T extends Resource> {
    onView?: (resourceId: T['id']) => void
    onEdit?: (resourceId: T['id']) => void
    onDelete?: (resourceId: T['id']) => Promise<void> | void
    extraActions?: ExtraAction<T>[]
    resource: T
}

export function DataTableActions<T extends Resource>({
    onView,
    onEdit,
    onDelete,
    resource,
    extraActions,
}: Readonly<Props<T>>) {
    return (
        <div className='flex justify-end pr-0'>
            <DropdownMenu>
                <DropdownMenuTrigger asChild>
                    <Button
                        variant='ghost'
                        className='group h-8 w-8 cursor-pointer p-0 transition-all duration-200 hover:shadow-md'
                    >
                        <span className='sr-only'>Open menu</span>
                        <MoreVertical className='h-4 w-4 transition-colors duration-200' />
                    </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align='end'>
                    {extraActions?.map(action => (
                        <DropdownMenuItem
                            key={action.key}
                            onClick={() => action.onClick(resource.id, resource)}
                            className={action.destructive ? 'text-destructive focus:text-destructive' : ''}
                        >
                            {action.icon}
                            {action.label}
                        </DropdownMenuItem>
                    ))}
                    {onView && (
                        <DropdownMenuItem onClick={() => onView(resource.id)}>
                            <Eye /> View
                        </DropdownMenuItem>
                    )}
                    {onEdit && (
                        <DropdownMenuItem onClick={() => onEdit(resource.id)}>
                            <SquarePen /> Edit
                        </DropdownMenuItem>
                    )}
                    {onDelete && (
                        <DropdownMenuItem
                            onClick={async () => await onDelete(resource.id)}
                            className='text-destructive focus:text-destructive'
                        >
                            <Trash2 color='red' /> Delete
                        </DropdownMenuItem>
                    )}
                </DropdownMenuContent>
            </DropdownMenu>
        </div>
    )
}

import { NumericFormat } from 'react-number-format'

import { Checkbox } from '@/components/ui/checkbox'
import { Input } from '@/components/ui/input'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Textarea } from '@/components/ui/textarea'

import { DatePicker } from '@/components/date-picker/date-picker'
import VirtualizedDropdown from '@/components/virtualized-dropdown'

import { FieldDef, Resource } from './types'

interface DataTableCellRendererProps<TData extends Resource> {
    field: FieldDef<TData>
    value: unknown
    onChange: (value: unknown) => void
    disabled?: boolean
    error?: string
}

export const DataTableCellRenderer = <TData extends Resource>({
    field,
    value,
    onChange,
    disabled,
    error,
}: DataTableCellRendererProps<TData>) => {
    return (
        <div className='flex flex-col gap-1'>
            <CellInput field={field} value={value} onChange={onChange} disabled={disabled} />
            {error && <span className='text-destructive text-xs'>{error}</span>}
        </div>
    )
}

interface CellInputProps<TData extends Resource> {
    field: FieldDef<TData>
    value: unknown
    onChange: (value: unknown) => void
    disabled?: boolean
}

const CellInput = <TData extends Resource>({ field, value, onChange, disabled }: CellInputProps<TData>) => {
    switch (field.type) {
        case 'text':
            return (
                <Input
                    value={typeof value === 'string' ? value : ''}
                    onChange={e => onChange(e.target.value)}
                    placeholder={field.placeholder}
                    disabled={disabled}
                    className='min-w-0'
                />
            )

        case 'number':
            return (
                <NumericFormat
                    value={typeof value === 'number' && !Number.isNaN(value) ? value : ''}
                    onValueChange={({ floatValue }) => {
                        if (floatValue === undefined || Number.isNaN(floatValue)) {
                            onChange(undefined)
                        } else {
                            onChange(floatValue)
                        }
                    }}
                    placeholder={field.placeholder}
                    decimalScale={field.decimalScale}
                    fixedDecimalScale={!!field.decimalScale}
                    thousandSeparator={field.thousandSeparator}
                    disabled={disabled}
                    customInput={Input}
                    className='min-w-0'
                />
            )

        case 'textarea':
            return (
                <Textarea
                    value={typeof value === 'string' ? value : ''}
                    onChange={e => onChange(e.target.value)}
                    placeholder={field.placeholder}
                    rows={field.rows ?? 2}
                    disabled={disabled}
                    className='w-full min-w-0 resize-none break-all'
                />
            )

        case 'checkbox':
            return (
                <Checkbox
                    checked={typeof value === 'boolean' ? value : false}
                    onCheckedChange={checked => onChange(checked)}
                    disabled={disabled}
                />
            )

        case 'date':
            return (
                <DatePicker
                    value={value instanceof Date ? value : undefined}
                    onValueChange={date => onChange(date)}
                    disabled={disabled}
                />
            )

        case 'select':
            return (
                <Select
                    value={typeof value === 'string' ? value : ''}
                    onValueChange={val => onChange(val)}
                    disabled={disabled}
                >
                    <SelectTrigger>
                        <SelectValue placeholder='Select...' />
                    </SelectTrigger>
                    <SelectContent>
                        {field.options.map(opt => (
                            <SelectItem key={opt.value} value={opt.value}>
                                {opt.label}
                            </SelectItem>
                        ))}
                    </SelectContent>
                </Select>
            )

        case 'readonly':
            return null

        case 'virtualized-dropdown':
            return (
                <VirtualizedDropdown
                    data={field.data as never}
                    single={field.single}
                    nameSet={field.nameSet as string}
                    idSet={field.idSet as string}
                    value={value as never}
                    onChange={selected => onChange(selected)}
                    customEmptyMessage={field.customEmptyMessage}
                    keepOpenOnSelect={field.keepOpenOnSelect}
                    disabled={disabled}
                />
            )

        default:
            return null
    }
}

import { useEffect, useState } from 'react'

import { TableCell, TableRow } from '@/components/ui/table'

import { DataTableCellRenderer } from './data-table-cell-renderer'
import { DataTableFormActions } from './data-table-form-actions'
import { ColumnMeta, FieldErrors, Resource } from './types'

interface DataTableCreateRowProps<TData extends Resource> {
    columns: ColumnMeta<TData>[]
    onCreate: (data: Partial<TData>) => Promise<void>
    isSubmitting?: boolean
    errors?: FieldErrors
    onCancel?: () => void
}

export function DataTableCreateRow<TData extends Resource>({
    columns,
    onCreate,
    isSubmitting = false,
    errors = {},
    onCancel,
}: DataTableCreateRowProps<TData>) {
    const [formData, setFormData] = useState<Partial<TData>>({})
    const [clearedFields, setClearedFields] = useState<Set<string>>(new Set())
    const [resetKey, setResetKey] = useState(0)

    const handleChange = (key: keyof TData, value: unknown) => {
        setClearedFields(prev => new Set(prev).add(String(key)))
        setFormData(prev => ({ ...prev, [key]: value }))
    }

    const handleSave = async () => {
        await onCreate(formData)
        setFormData({})
        setClearedFields(new Set())
    }

    const handleCancel = () => {
        setFormData({})
        setClearedFields(new Set())
        setResetKey(prev => prev + 1)
        onCancel?.()
    }

    const mergedErrors: FieldErrors = Object.fromEntries(
        Object.entries(errors).filter(([key]) => !clearedFields.has(key)),
    )

    const isDirty = Object.keys(formData).length > 0

    useEffect(() => {
        if (errors && Object.keys(errors).length > 0) {
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setClearedFields(new Set())
        }
    }, [errors])
    return (
        <TableRow key={resetKey} className='bg-muted/60 hover:bg-muted/60 border-primary/20 border-b-2'>
            {columns.map(col => {
                const field = col.field
                return (
                    <TableCell
                        key={String(col.key)}
                        className='border-border border-r last:border-r-0'
                        style={
                            col.size !== undefined
                                ? {
                                      minWidth: `${col.size}px`,
                                      width: `${col.size}px`,
                                  }
                                : undefined
                        }
                    >
                        {field && field.type !== 'readonly' ? (
                            <DataTableCellRenderer
                                field={field}
                                value={formData[col.key] ?? ''}
                                onChange={val => handleChange(col.key, val)}
                                disabled={isSubmitting}
                                error={mergedErrors[String(col.key)]}
                            />
                        ) : null}
                    </TableCell>
                )
            })}
            <TableCell style={{ width: '1px', whiteSpace: 'nowrap' }}>
                <DataTableFormActions
                    onSave={handleSave}
                    onCancel={handleCancel}
                    isSubmitting={isSubmitting}
                    disabled={!isDirty}
                />
            </TableCell>
        </TableRow>
    )
}

import { useEffect, useState } from 'react'

import { isSameDay } from 'date-fns'

import { TableCell, TableRow } from '@/components/ui/table'

import { DataTableCellRenderer } from './data-table-cell-renderer'
import { DataTableFormActions } from './data-table-form-actions'
import { ColumnMeta, FieldErrors, Resource } from './types'

interface DataTableEditRowProps<TData extends Resource> {
    row: TData
    columns: ColumnMeta<TData>[]
    onSave: (id: TData['id'], data: Partial<TData>) => Promise<void>
    onCancel: () => void
    isSubmitting?: boolean
    errors?: FieldErrors
}

export function DataTableEditRow<TData extends Resource>({
    row,
    columns,
    onSave,
    onCancel,
    isSubmitting = false,
    errors = {},
}: DataTableEditRowProps<TData>) {
    const getInitialFormData = () => {
        const initial: Partial<TData> = { ...row }
        columns.forEach(col => {
            const field = col.field
            if (field?.getInitialValue) {
                initial[col.key] = field.getInitialValue(row) as TData[keyof TData]
            }
        })
        return initial
    }

    const [formData, setFormData] = useState<Partial<TData>>(getInitialFormData)
    const [clearedFields, setClearedFields] = useState<Set<string>>(new Set())

    const handleChange = (key: keyof TData, value: unknown) => {
        setClearedFields(prev => new Set(prev).add(String(key)))
        setFormData(prev => ({ ...prev, [key]: value }))
    }

    const handleSave = async () => {
        await onSave(row.id, formData)
    }

    const handleCancel = () => {
        setClearedFields(new Set())
        onCancel()
    }

    const mergedErrors: FieldErrors = Object.fromEntries(
        Object.entries(errors).filter(([key]) => !clearedFields.has(key)),
    )

    const isDirty = !isEqual(formData, row)
    console.log('formData.start_date', formData.start_date)
    console.log('row.start_date', row.start_date)
    console.log('isEqual result', isEqual(formData.start_date, row.start_date))
    console.log('isDirty', isDirty)

    useEffect(() => {
        if (errors && Object.keys(errors).length > 0) {
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setClearedFields(new Set())
        }
    }, [errors])

    return (
        <TableRow className='bg-blue-50/40 hover:bg-blue-50/40 dark:bg-blue-950/20 dark:hover:bg-blue-950/20'>
            {columns.map(col => {
                const field = col.field
                return (
                    <TableCell
                        key={String(col.key)}
                        className='border-border border-r last:border-r-0'
                        style={
                            col.size !== undefined
                                ? {
                                      minWidth: `${col.size}px`,
                                      width: `${col.size}px`,
                                  }
                                : undefined
                        }
                    >
                        {field && field.type !== 'readonly' ? (
                            <DataTableCellRenderer
                                field={field}
                                value={formData[col.key] ?? ''}
                                onChange={val => handleChange(col.key, val)}
                                disabled={isSubmitting}
                                error={mergedErrors[String(col.key)]}
                            />
                        ) : (
                            <span className='text-muted-foreground text-sm'>
                                {field?.render
                                    ? field.render(formData[col.key] as TData[keyof TData], formData as TData)
                                    : String(formData[col.key] ?? '—')}
                            </span>
                        )}
                    </TableCell>
                )
            })}
            <TableCell style={{ width: '1px', whiteSpace: 'nowrap' }}>
                <DataTableFormActions
                    onSave={handleSave}
                    onCancel={handleCancel}
                    isSubmitting={isSubmitting}
                    disabled={!isDirty}
                />
            </TableCell>
        </TableRow>
    )
}

function isEqual(a: unknown, b: unknown): boolean {
    if (a === b) return true
    if (a instanceof Date && b instanceof Date) return isSameDay(a, b)
    if (a === null || b === null) return a === b
    if (typeof a !== 'object' || typeof b !== 'object') return a === b
    if (Array.isArray(a) && Array.isArray(b)) {
        if (a.length !== b.length) return false
        return a.every((item, i) => isEqual(item, b[i]))
    }
    if (Array.isArray(a) !== Array.isArray(b)) return false
    const keysA = Object.keys(a as object)
    const keysB = Object.keys(b as object)
    if (keysA.length !== keysB.length) return false
    return keysA.every(key => isEqual((a as Record<string, unknown>)[key], (b as Record<string, unknown>)[key]))
}

import { useEffect, useState } from 'react'

import { ChevronLeftIcon, ChevronRightIcon } from 'lucide-react'

import { Button } from '@/components/ui/button'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'

import { PaginationState } from './types'

interface DataTablePaginationProps {
    pagination: PaginationState
}

export function DataTablePagination({ pagination }: DataTablePaginationProps) {
    const { page, pageSize, total, onPageChange, onPageSizeChange } = pagination
    const [isLoading, setIsLoading] = useState(false)

    const totalPages = Math.ceil(total / pageSize)
    const canPrevious = page > 0
    const canNext = page < totalPages - 1

    useEffect(() => {
        // eslint-disable-next-line react-hooks/set-state-in-effect
        setIsLoading(false)
    }, [page])

    const handlePrevious = () => {
        if (isLoading || !canPrevious) return
        setIsLoading(true)
        onPageChange(page - 1)
    }

    const handleNext = () => {
        if (isLoading || !canNext) return
        setIsLoading(true)
        onPageChange(page + 1)
    }

    const handlePageClick = (targetPage: number) => {
        if (targetPage === page) return
        onPageChange(targetPage)
    }

    // show 3 pages starting from current
    const pageButtons = Array.from({ length: 3 })
        .map((_, idx) => page + idx)
        .filter(p => p < totalPages)

    return (
        <div className='mt-2 flex w-full flex-col items-center justify-between space-y-4 px-2 lg:flex-row lg:space-y-0'>
            <div className='flex items-center space-x-2'>
                <p className='text-sm font-medium'>Rows per page</p>
                <Select value={`${pageSize}`} onValueChange={value => onPageSizeChange(Number(value))}>
                    <SelectTrigger className='h-8 w-[70px] rounded-sm py-5 hover:cursor-pointer focus:ring-neutral-300'>
                        <SelectValue placeholder={pageSize} />
                    </SelectTrigger>
                    <SelectContent side='top'>
                        {[10, 50, 100, 150, 200].map(size => (
                            <SelectItem key={size} value={`${size}`} className='hover:cursor-pointer'>
                                {size}
                            </SelectItem>
                        ))}
                    </SelectContent>
                </Select>
            </div>

            <div className='flex items-center space-x-2'>
                <Button
                    variant='ghost'
                    className='cursor-pointer'
                    onClick={handlePrevious}
                    disabled={!canPrevious || isLoading}
                >
                    <ChevronLeftIcon className='h-4 w-4' />
                    Previous
                </Button>

                <div className='flex items-center justify-center space-x-1 text-sm font-medium'>
                    {pageButtons.map(p => (
                        <Button
                            key={p}
                            variant={p === page ? 'outline' : 'ghost'}
                            className='cursor-pointer rounded-sm'
                            onClick={() => handlePageClick(p)}
                        >
                            {p + 1}
                        </Button>
                    ))}
                </div>

                <Button
                    variant='ghost'
                    className='cursor-pointer'
                    onClick={handleNext}
                    disabled={!canNext || isLoading}
                >
                    Next
                    <ChevronRightIcon className='h-4 w-4' />
                </Button>
            </div>
        </div>
    )
}

import { Spinner } from '@/components/ui/spinner'

type Props = {
    isFetching: boolean
}

export function DataTableProgressSpinner({ isFetching }: Readonly<Props>) {
    if (isFetching) {
        return (
            <div className='absolute z-20 flex h-full w-full items-center justify-center bg-gray-100/50'>
                <Spinner className='size-6' />
            </div>
        )
    }

    return null
}
